class Solution:
    def minTime(self, n, edges, hasApple):
        from collections import defaultdict
        adj = defaultdict(list)
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        def dfs(node, parent):
            total = 0
            for child in adj[node]:
                if child == parent:
                    continue
                sub = dfs(child, node)
                if sub > 0 or hasApple[child]:
                    total += sub + 2
            return total
        return dfs(0, -1)

